#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <cstdint>
#include <omp.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

#define OMP_CHECK(x) do { \
    int err = (x); \
    if (err != 0) { \
        printf("OpenMP error %s:%d: %d\n", __FILE__, __LINE__, err); \
        exit(1); \
    } \
} while (0)

template<typename T>
void conv1d_kernel(const T* __restrict__ in,
                   T* __restrict__ out,
                   const T* __restrict__ mask,
                   const int input_width,
                   const int mask_width,
                   const int grids,
                   const int bs)
{
  (void)grids;
  #pragma omp target teams distribute parallel for is_device_ptr(in, out, mask) num_teams(grids) thread_limit(bs)
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      int idx = start + j;
      if (idx >= 0 && idx < input_width) {
        s += in[idx] * mask[j];
      }
    }
    out[i] = s;
  }
}

